"use strict";(globalThis.webpackChunk_servicenow_sdk_docs=globalThis.webpackChunk_servicenow_sdk_docs||[]).push([[367389],{248152(e){e.exports=JSON.parse('{"tag":{"label":"knowledge base","permalink":"/sdk/tags/knowledge-base","allTagsPath":"/sdk/tags","count":1,"items":[{"id":"guides/user-criteria-guide","title":"User Criteria","description":"User Criteria (user_criteria) are named, reusable access conditions that determine which users can view catalog items, knowledge articles, service portal topics, and other platform content. Required for controlling Service Catalog item visibility\u2014always use instead of ACLs or the roles property for who can see/order catalog items. Unlike ACLs\u2014which control read/write/delete operations on database records\u2014User Criteria define audience membership based on combinations of users, groups, roles, departments, locations, companies, and optional scripts.","permalink":"/sdk/guides/user-criteria-guide"}],"unlisted":false}}')}}]);